-- 0010 Script Node Engine — library seed (generated from lib/script-engine/data).
-- Regenerate: GEN_SEED=1 npx vitest run lib/script-engine/data/library.test.ts

-- recipes must exist before compat_rules (FK).
on conflict (id) do update set name_vi=excluded.name_vi,pillar=excluded.pillar,preferred_hooks=excluded.preferred_hooks,allowed_hooks=excluded.allowed_hooks,payoff_tags=excluded.payoff_tags,chain=excluded.chain;

on conflict (id) do update set family=excluded.family,text_template=excluded.text_template,onscreen_text=excluded.onscreen_text,visual_directive=excluded.visual_directive,duration_min=excluded.duration_min,duration_max=excluded.duration_max,word_min=excluded.word_min,word_max=excluded.word_max,requires_slots=excluded.requires_slots,optional_slots=excluded.optional_slots,promise_tags=excluded.promise_tags,tone_tags=excluded.tone_tags,platform_fit=excluded.platform_fit,risk_level=excluded.risk_level,weight=excluded.weight,status=excluded.status;

on conflict (id) do update set node_type=excluded.node_type,text_template=excluded.text_template,onscreen_text=excluded.onscreen_text,visual_directive=excluded.visual_directive,duration_min=excluded.duration_min,duration_max=excluded.duration_max,word_min=excluded.word_min,word_max=excluded.word_max,requires_slots=excluded.requires_slots,optional_slots=excluded.optional_slots,delivers_tag=excluded.delivers_tag,funnel=excluded.funnel,tone_tags=excluded.tone_tags,platform_fit=excluded.platform_fit,weight=excluded.weight,status=excluded.status;

on conflict (hook_family,content_type) do update set level=excluded.level;

on conflict (key) do update set slot_group=excluded.slot_group,data_type=excluded.data_type,source_path=excluded.source_path,formatter=excluded.formatter,computed_formula=excluded.computed_formula,fallback_text=excluded.fallback_text,requires_source=excluded.requires_source;
